mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_SERVER_BENCH_SOLUTION_EOF'
import { randomUUID } from "node:crypto";

const port = Number(Bun.env.PORT ?? 3000);
const WORKERS = 4;
const MAX_KEY_DEPTH = 50;

type QueueJob = {
  id: string;
  key: string;
  payload: string;
  attempts: number;
};

type ProcessedItem = {
  id: string;
  key: string;
  payload: string;
  key_sequence: number;
};

const perKeyQueues = new Map<string, QueueJob[]>();
const busyKeys = new Set<string>();
const keySequence = new Map<string, number>();
const processed: ProcessedItem[] = [];
const processedIds = new Set<string>();
const inFlight = new Map<string, string>();
const failOnceSeen = new Set<string>();
const crashAttempted = new Set<string>();

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function queueDepth(key: string): number {
  return perKeyQueues.get(key)?.length ?? 0;
}

function enqueueJob(key: string, payload: string): QueueJob | "backpressure" {
  const depth = queueDepth(key) + (busyKeys.has(key) ? 1 : 0);
  if (depth >= MAX_KEY_DEPTH) {
    return "backpressure";
  }
  const job: QueueJob = { id: randomUUID(), key, payload, attempts: 0 };
  const queue = perKeyQueues.get(key) ?? [];
  queue.push(job);
  perKeyQueues.set(key, queue);
  return job;
}

function pickKey(): string | null {
  for (const [key, queue] of perKeyQueues) {
    if (queue.length > 0 && !busyKeys.has(key)) {
      return key;
    }
  }
  return null;
}

async function runPayload(job: QueueJob): Promise<"ok" | "retry" | "crash"> {
  if (job.payload.startsWith("slow:")) {
    const ms = Number(job.payload.slice("slow:".length));
    await sleep(Number.isFinite(ms) ? ms : 50);
    return "ok";
  }

  if (job.payload.startsWith("fail-once:")) {
    const marker = job.payload;
    if (!failOnceSeen.has(marker)) {
      failOnceSeen.add(marker);
      return "retry";
    }
    return "ok";
  }

  if (job.payload === "crash") {
    if (!crashAttempted.has(job.id)) {
      crashAttempted.add(job.id);
      return "crash";
    }
    return "ok";
  }

  return "ok";
}

function markProcessed(job: QueueJob): void {
  if (processedIds.has(job.id)) {
    return;
  }
  processedIds.add(job.id);
  const seq = (keySequence.get(job.key) ?? 0) + 1;
  keySequence.set(job.key, seq);
  processed.push({
    id: job.id,
    key: job.key,
    payload: job.payload,
    key_sequence: seq,
  });
}

async function workerLoop(): Promise<void> {
  for (;;) {
    const key = pickKey();
    if (!key) {
      await sleep(2);
      continue;
    }

    busyKeys.add(key);
    const queue = perKeyQueues.get(key)!;
    const job = queue.shift()!;
    if (queue.length === 0) {
      perKeyQueues.delete(key);
    }

    inFlight.set(key, job.id);
    job.attempts += 1;
    const outcome = await runPayload(job);
    inFlight.delete(key);
    busyKeys.delete(key);

    if (outcome === "ok") {
      markProcessed(job);
      continue;
    }

    const requeue = perKeyQueues.get(key) ?? [];
    requeue.unshift(job);
    perKeyQueues.set(key, requeue);
  }
}

for (let i = 0; i < WORKERS; i += 1) {
  void workerLoop();
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "GET" && url.pathname === "/processed") {
      return Response.json({ items: processed }, { status: 200 });
    }

    if (request.method === "GET" && url.pathname === "/status") {
      return Response.json(
        {
          in_flight: [...inFlight.entries()].map(([key, id]) => ({ key, id })),
          workers: WORKERS,
        },
        { status: 200 },
      );
    }

    if (request.method === "POST" && url.pathname === "/enqueue") {
      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const record = body as Record<string, unknown> | null;
      if (!record || typeof record.key !== "string" || typeof record.payload !== "string") {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      if (record.key.length === 0) {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }

      const job = enqueueJob(record.key, record.payload);
      if (job === "backpressure") {
        return Response.json({ error: "backpressure" }, { status: 429 });
      }
      return Response.json({ id: job.id, key: job.key, queued: true }, { status: 202 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`per-key-fifo reference listening on ${port}`);
BUN_SERVER_BENCH_SOLUTION_EOF
